import './App.css';
import Navbar from './componentes/navbar';
import Footer from './componentes/footer';
import abogadas from './componentes/abogadas';
function App() {
  return (
    <div className="App">
    <header className="header">
      <Navbar />
    </header>
    <body className='body'>
      <div className='Principal'>


      </div>

      <div className='Abogadas'>
        <abogadas nombre="Maria Perez" imagen="https://via.placeholder.com/150" especialidades={["Derecho Civil", "Derecho Penal"]} />
        <abogadas nombre="Ana Gomez" imagen="https://via.placeholder.com/150" especialidades={["Derecho Laboral", "Derecho de Familia"]} />
        <abogadas nombre="Laura Rodriguez" imagen="https://via.placeholder.com/150" especialidades={["Derecho Mercantil", "Derecho Tributario"]} />
      </div>
    </body>

      <footer>
        <Footer />
      </footer>

    </div>
  );
}

export default App;
